      status: 'pending_review',
      confidenceScore: 8,
      impactScore: 6,
      triageScore: '68',
      metadataJson: { manual: true, dedupeHash },
    })
    .returning({ id: macroRelationships.id });
  if (!relationship) throw new Error('Macro relationship insert returned no row.');

