      );
    }

    // Step 5 — seeds.
    console.log('Step 5: seed (settings + admin employee)');
    await runSeed(client);

    console.log('\nMigrations + seed complete.');
  } finally {
    await client.end({ timeout: 5 });
  }
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

